/**
 * DNA | Profile & Identity Hub — Cross-C Identity Type System
 *
 * The Profile is where every C converges. It is not a static page — it is a
 * living, breathing representation of a user's entire DNA journey: who they
 * connect with, events they convene, spaces they collaborate in, value they
 * contribute, and stories they convey.
 *
 * Four Identity Layers:
 * - Layer 1: Professional Identity (Foundation — user-entered)
 * - Layer 2: Diaspora Identity (Cultural — user-curated)
 * - Layer 3: Activity (Living — auto-populated from Five C's)
 * - Layer 4: Impact (Emergent — generated by DIA)
 *
 * Dependencies: DIA Core Engine, Feed Architecture, Post Composer,
 *               Notification System, Messaging System
 */

import type { FiveCModule, SubscriptionTier } from './dia';

// ============================================================
// PROFILE — Core Identity
// ============================================================

export interface IdentityHubProfile {
  id: string;
  userId: string;

  // ── Layer 1: Professional Identity ──
  displayName: string;
  firstName: string;
  lastName: string;
  headline: string | null;
  bio: string | null;
  avatarUrl: string | null;
  coverImageUrl: string | null;
  location: ProfileLocation;
  pronouns: string | null;

  // Professional
  skills: ProfileSkill[];
  interests: ProfileInterest[];
  industry: string | null;
  experience: ProfileExperience[];
  education: ProfileEducation[];
  socialLinks: ProfileSocialLink[];

  // ── Layer 2: Diaspora Identity ──
  heritage: DiasporaHeritage;

  // ── Layer 3: Activity (auto-populated) ──
  activitySummary: FiveCActivitySummary;

  // ── Layer 4: Impact (DIA-generated) ──
  impactScore: FiveCImpactScore;
  badges: ProfileBadge[];
  diaInsight: string | null;

  // Profile meta
  completionPercentage: number;
  completionChecklist: CompletionChecklistItem[];
  verificationStatus: VerificationStatus;
  tier: UserTier;
  visibility: ProfileVisibility;
  profileViews: number;
  lastActiveAt: Date;
  joinedAt: Date;
  updatedAt: Date;
}

// ============================================================
// LOCATION
// ============================================================

export interface ProfileLocation {
  city: string | null;
  state: string | null;
  country: string;
  countryCode: string;
  timezone: string;
  coordinates: {
    latitude: number;
    longitude: number;
  } | null;
  displayFormat: string;
}

// ============================================================
// SKILLS & INTERESTS
// ============================================================

export interface ProfileSkill {
  id: string;
  name: string;
  category: SkillCategory;
  endorsementCount: number;
  endorsedBy: string[];
  isTopSkill: boolean;
  diaStrength: number;
  source: 'user_added' | 'dia_suggested' | 'endorsed';
}

export type SkillCategory =
  | 'technical' | 'business' | 'creative' | 'leadership'
  | 'research' | 'community' | 'language' | 'industry_specific';

export interface ProfileInterest {
  id: string;
  name: string;
  category: InterestCategory;
  addedAt: Date;
}

export type InterestCategory =
  | 'professional' | 'cultural' | 'geographic' | 'topical'
  | 'industry' | 'cause' | 'community';

// ============================================================
// DIASPORA HERITAGE (Layer 2)
// ============================================================

export interface DiasporaHeritage {
  heritageCountries: HeritageCountry[];
  currentCountry: string;
  languages: HeritageLanguage[];
  diasporaGeneration: DiasporaGeneration | null;
  culturalInterests: string[];
  diasporaEngagement: DiasporaEngagementLevel;
  regionalConnections: RegionalConnection[];
}

export interface HeritageCountry {
  countryCode: string;
  countryName: string;
  relationship: 'born' | 'ancestry' | 'lived' | 'connected';
  region: AfricanRegion;
  isPrimary: boolean;
}

export interface HeritageLanguage {
  language: string;
  proficiency: 'native' | 'fluent' | 'conversational' | 'learning';
  isHeritage: boolean;
}

export type DiasporaGeneration =
  | 'first'
  | 'second'
  | 'third_plus'
  | 'returnee'
  | 'continental'
  | 'ally';

export type DiasporaEngagementLevel =
  | 'exploring'
  | 'connecting'
  | 'contributing'
  | 'leading'
  | 'transforming';

export type AfricanRegion =
  | 'west_africa' | 'east_africa' | 'southern_africa'
  | 'north_africa' | 'central_africa';

export interface RegionalConnection {
  region: AfricanRegion;
  connectionCount: number;
  strength: 'strong' | 'moderate' | 'emerging';
}

// ============================================================
// EXPERIENCE & EDUCATION
// ============================================================

export interface ProfileExperience {
  id: string;
  title: string;
  organization: string;
  organizationLogoUrl: string | null;
  location: string | null;
  startDate: Date;
  endDate: Date | null;
  isCurrent: boolean;
  description: string | null;
  skills: string[];
  isAfricaFocused: boolean;
}

export interface ProfileEducation {
  id: string;
  institution: string;
  degree: string | null;
  fieldOfStudy: string | null;
  startYear: number;
  endYear: number | null;
  description: string | null;
  isHBCU: boolean;
  isAfricanInstitution: boolean;
}

// ============================================================
// SOCIAL LINKS
// ============================================================

export interface ProfileSocialLink {
  platform: SocialPlatform;
  url: string;
  username: string | null;
}

export type SocialPlatform =
  | 'linkedin' | 'twitter' | 'instagram' | 'github'
  | 'website' | 'youtube' | 'tiktok' | 'medium'
  | 'substack' | 'behance' | 'dribbble' | 'other';

// ============================================================
// FIVE C's ACTIVITY SUMMARY (Layer 3)
// ============================================================

export interface FiveCActivitySummary {
  connect: {
    connectionCount: number;
    countrySpan: number;
    recentConnectionCount: number;
    mutualConnectionsWithViewer: number;
  };
  convene: {
    eventsHosted: number;
    eventsAttended: number;
    upcomingEvents: number;
    totalAttendees: number;
  };
  collaborate: {
    spacesActive: number;
    spacesLed: number;
    tasksCompleted: number;
    collaboratorsCount: number;
  };
  contribute: {
    opportunitiesPosted: number;
    opportunitiesFulfilled: number;
    offersActive: number;
    needsActive: number;
  };
  convey: {
    storiesPublished: number;
    totalEngagement: number;
    followerCount: number;
    avgEngagementRate: number;
  };
}

// ============================================================
// FIVE C's IMPACT SCORE (Layer 4 — DIA-generated)
// ============================================================

export type CModule = FiveCModule;

export interface FiveCImpactScore {
  overall: number;
  connect: number;
  convene: number;
  collaborate: number;
  contribute: number;
  convey: number;
  lastComputedAt: Date;
  trend: 'rising' | 'stable' | 'declining';
  percentileRank: number;
  strongestC: CModule;
  growthOpportunityC: CModule;
}

