// ============================================================
// PROFILE VIEW CONTEXT
// ============================================================

export type ProfileViewContext =
  | 'own_profile'
  | 'connected'
  | 'not_connected'
  | 'search_result'
  | 'dia_suggestion'
  | 'event_attendee'
  | 'space_member'
  | 'opportunity_poster';

export interface ParticipantPreview {
  id: string;
  displayName: string;
  avatarUrl: string | null;
  headline: string | null;
}

export interface ProfileViewPayload {
  profile: IdentityHubProfile;
  viewContext: ProfileViewContext;
  viewerRelationship: {
    isConnected: boolean;
    isPending: boolean;
    mutualConnectionCount: number;
    mutualConnections: ParticipantPreview[];
    sharedSpaces: { id: string; name: string }[];
    sharedEvents: { id: string; name: string }[];
    relationshipStrength: number | null;
  };
  diaMatchInfo: {
    matchScore: number | null;
    matchType: string | null;
    matchReasons: string[];
  } | null;
  visibleSections: ProfileSection[];
}

